"""
Minimal shim for Michele Simionato's `decorator` package.

Manim's `manim/utils/deprecation.py` uses exactly two names from this
package:

    from decorator import decorate, decorator

We don't ship the upstream `decorator` wheel because it pulls in
`inspect.Signature`-based source-rewriting that we don't need on iOS,
and because it was the lone unmet dep blocking `from manim import *`
in the in-app shell.

This module provides functionally-equivalent versions of just those
two names — `decorate(func, caller)` and `decorator(caller)` — using
`functools.wraps` for signature/metadata preservation. Anything else
from the upstream API (FunctionMaker, contextmanager, dispatch_on,
…) is intentionally absent; importing it raises AttributeError so
the gap is loud rather than silent.
"""
from __future__ import annotations

import functools
import inspect
from typing import Any, Callable

__version__ = "5.1.1-offlinai-shim"
__all__ = ["decorate", "decorator"]


def decorate(func: Callable[..., Any],
             caller: Callable[..., Any]) -> Callable[..., Any]:
    """Return a wrapped version of `func` that delegates each call to
    `caller(func, *args, **kwargs)`.

    Mirrors `decorator.decorate` from the upstream package. The wrapper
    keeps `func`'s name, docstring, qualname, module, annotations, and
    `__wrapped__` reference (via `functools.wraps`) so introspection
    tools like Sphinx / pydoc / IDEs see the original signature."""

    @functools.wraps(func)
    def _wrapper(*args: Any, **kwargs: Any) -> Any:
        return caller(func, *args, **kwargs)

    # Preserve the parameter signature for tools that do their own
    # `inspect.signature(...)` lookup (functools.wraps copies the
    # __wrapped__ attribute, which inspect.signature follows). Just to
    # be defensive against tools that explicitly read __signature__,
    # set it too.
    try:
        _wrapper.__signature__ = inspect.signature(func)
    except (TypeError, ValueError):
        # Builtins or C-extensions sometimes refuse signature inspection;
        # the wrapper still works, callers just lose rich introspection.
        pass
    return _wrapper


def decorator(caller: Callable[..., Any]) -> Callable[..., Any]:
    """Turn a `caller(func, *args, **kwargs)` function into a decorator
    factory.

    Used like::

        @decorator
        def trace(func, *args, **kwargs):
            print(f"calling {func.__name__}")
            return func(*args, **kwargs)

        @trace
        def add(x, y): return x + y

    Equivalent to::

        def trace(func):
            return decorate(func, _trace_caller)
    """

    @functools.wraps(caller)
    def _factory(func: Callable[..., Any]) -> Callable[..., Any]:
        return decorate(func, caller)

    return _factory
